import { useEffect, useRef } from 'react';
export const useBlurOnFulfill = ({ value, cellCount, }) => {
    'use memo';
    const inputRef = useRef(null);
    useEffect(() => {
        if (value?.length === cellCount) {
            inputRef.current?.blur();
        }
    }, [value, cellCount]);
    return inputRef;
};
